diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..b0a3946387b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -667,8 +667,40 @@ static Value *foldLogOpOfMaskedICmps(Value *LHS, Value *RHS, bool IsAnd,
         const APInt ConstC = PredL != CC ? *ConstB ^ *OldConstC : *OldConstC;
         const APInt ConstE = PredR != CC ? *ConstD ^ *OldConstE : *OldConstE;

-        if (((*ConstB & *ConstD) & (ConstC ^ ConstE)).getBoolValue())
+        if (((*ConstB & *ConstD) & (ConstC ^ ConstE)).getBoolValue()) {
+          // If one side has a trivial mask (all ones), that side is just a
+          // simple equality (A == C or A == E), and the other side defines a
+          // range via its mask. The OR of a point and an adjacent range can be
+          // converted into a single range check.
+          // For example:
+          //   (icmp eq A, 127) | (icmp eq (A & -32), 128)
+          //   -> (icmp ult (A - 127), 33)
+          if (IsNot && (ConstB->isAllOnes() || ConstD->isAllOnes())) {
+            // Determine which side is the point (all-ones mask) and which is the
+            // range (non-all-ones mask).
+            bool BIsPoint = ConstB->isAllOnes();
+            const APInt &PointC = BIsPoint ? ConstC : ConstE;
+            const APInt &RangeMask = BIsPoint ? *ConstD : *ConstB;
+            const APInt &RangeC = BIsPoint ? ConstE : ConstC;
+
+            // The range is [RangeC, RangeC | ~RangeMask] since RangeMask &
+            // RangeC == RangeC. Check if PointC is just below or just above.
+            APInt RangeEnd = RangeC | ~RangeMask;
+            if (PointC + 1 == RangeC) {
+              // Point is just below the range: [PointC, RangeEnd].
+              APInt Size = RangeEnd - PointC + 1;
+              Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), -PointC));
+              return Builder.CreateICmpULT(Add, ConstantInt::get(A->getType(), Size));
+            }
+            if (PointC == RangeEnd + 1) {
+              // Point is just above the range: [RangeC, PointC].
+              APInt Size = PointC - RangeC + 1;
+              Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), -RangeC));
+              return Builder.CreateICmpULT(Add, ConstantInt::get(A->getType(), Size));
+            }
+          }
           return IsNot ? nullptr : ConstantInt::get(LHS->getType(), !IsAnd);
+        }

         if (IsNot && !ConstB->isSubsetOf(*ConstD) &&
             !ConstD->isSubsetOf(*ConstB))

